BEGIN
{
  printf("Tracing key VFS calls... Hit Ctrl-C to end.\n");
}

kprobe:vfs_read*,
kprobe:vfs_write*,
kprobe:vfs_fsync,
kprobe:vfs_open,
kprobe:vfs_create
{
  @[func] = count();
}

interval:1s
{
  time();
  print(@);
  clear(@);
}

END
{
  clear(@);
}
